var minimalMessages = []agentTypes.Message{
	{Role: "user", Content: "say ok"},
}

func assertSend(t *testing.T, send func(context.Context) (*agentTypes.Output, error)) {
	t.Helper()
	ctx, cancel := context.WithTimeout(context.Background(), 60*time.Second)
	defer cancel()
	out, err := send(ctx)
	if err != nil {
		t.Fatalf("Send: %v", err)
	}
	if len(out.Choices) == 0 {
		t.Fatal("no choices")
	}
	content, _ := out.Choices[0].Message.Content.(string)
	if content == "" {
		t.Fatal("empty content")
	}
	t.Logf("response: %s", content)
}

func TestProviderClaude(t *testing.T) {
	if keychain.Get("ANTHROPIC_API_KEY") == "" {
		t.Skip("ANTHROPIC_API_KEY not set")
	}
	for model := range provider.Models("claude") {
		model := model
		t.Run(model, func(t *testing.T) {
			t.Parallel()
			agent, err := claude.New(fmt.Sprintf("claude@%s", model))
			if err != nil {
				t.Fatalf("claude.New: %v", err)
			}
			assertSend(t, func(ctx context.Context) (*agentTypes.Output, error) {
				return agent.Send(ctx, minimalMessages, nil)
			})
		})
	}
}

