func TestProviderCopilot(t *testing.T) {
	homeDir, err := os.UserHomeDir()
	if err != nil {
		t.Skip("cannot determine home dir")
	}
	tokenFile := filepath.Join(homeDir, ".config", "agenvoy", "copilot_token.json")
	if _, err := os.Stat(tokenFile); os.IsNotExist(err) {
		t.Skip("copilot_token.json not found, run agenvoy login copilot first")
	}
	for model := range provider.Models("copilot") {
		model := model
		t.Run(model, func(t *testing.T) {
			t.Parallel()
			agent, err := copilot.New(fmt.Sprintf("copilot@%s", model))
			if err != nil {
				t.Fatalf("copilot.New: %v", err)
			}
			assertSend(t, func(ctx context.Context) (*agentTypes.Output, error) {
				return agent.Send(ctx, minimalMessages, nil)
			})
		})
	}
}
